import{_ as i,c as a,o as l,ae as t}from"./chunks/framework.CDjunVez.js";const u=JSON.parse('{"title":"Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"roadmap/index.md","filePath":"roadmap/index.md"}'),o={name:"roadmap/index.md"};function n(r,e,s,p,c,d){return l(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>This roadmap outlines the planned direction of KiwiPanel.<br> Timelines may change based on stability, real-world usage, and community feedback.</p><hr><h3 id="phase-0-—-foundation-pre-alpha-✅" tabindex="-1">Phase 0 — Foundation (Pre-Alpha) ✅ <a class="header-anchor" href="#phase-0-—-foundation-pre-alpha-✅" aria-label="Permalink to &quot;Phase 0 — Foundation (Pre-Alpha) ✅&quot;">​</a></h3><p><strong>Goal:</strong> Build a clean, inspectable core with minimal abstraction.</p><ul><li>[x] Installer bootstrap for supported Linux distributions</li><li>[x] Go-based backend architecture</li><li>[x] CLI framework (<code>kiwipanel</code>)</li><li>[x] SQLite-based local state</li><li>[x] System inspection (<code>kiwipanel check</code>)</li><li>[x] OpenLiteSpeed + MariaDB + PHP provisioning</li><li>[x] Clear separation between panel logic and system tooling</li><li>[x] Structured logging and error handling</li></ul><hr><h3 id="phase-1-—-php-stack-flexibility-alpha" tabindex="-1">Phase 1 — PHP &amp; Stack Flexibility (Alpha) <a class="header-anchor" href="#phase-1-—-php-stack-flexibility-alpha" aria-label="Permalink to &quot;Phase 1 — PHP &amp; Stack Flexibility (Alpha)&quot;">​</a></h3><p><strong>Goal:</strong> Support multiple PHP versions and improve stack flexibility.</p><ul><li>[ ] Install and manage <strong>multiple PHP versions</strong></li><li>[ ] Per-site PHP version selection</li><li>[ ] PHP-FPM pool management</li><li>[ ] Safe switching between PHP versions</li><li>[ ] PHP configuration templates (php.ini, extensions)</li><li>[ ] CLI and Web UI parity for PHP management</li><li>[ ] Clear conflict detection between PHP runtimes</li></ul><hr><h3 id="phase-2-—-web-server-choice-beta" tabindex="-1">Phase 2 — Web Server Choice (Beta) <a class="header-anchor" href="#phase-2-—-web-server-choice-beta" aria-label="Permalink to &quot;Phase 2 — Web Server Choice (Beta)&quot;">​</a></h3><p><strong>Goal:</strong> Allow users to choose their preferred web server without lock-in.</p><ul><li>[ ] <strong>Nginx</strong> support (PHP-FPM)</li><li>[ ] <strong>Apache</strong> support (MPM + PHP-FPM)</li><li>[ ] Web server selection at install time</li><li>[ ] Safe migration between web servers (manual, explicit)</li><li>[ ] Per-site virtual host management</li><li>[ ] TLS integration across all supported web servers</li><li>[ ] Log viewing for all web servers</li></ul><hr><h3 id="phase-3-—-database-engine-expansion-beta" tabindex="-1">Phase 3 — Database Engine Expansion (Beta) <a class="header-anchor" href="#phase-3-—-database-engine-expansion-beta" aria-label="Permalink to &quot;Phase 3 — Database Engine Expansion (Beta)&quot;">​</a></h3><p><strong>Goal:</strong> Support multiple database engines with the same transparent approach.</p><ul><li>[ ] <strong>MySQL</strong> support (Oracle MySQL)</li><li>[ ] <strong>PostgreSQL</strong> support</li><li>[ ] Database engine selection at install time</li><li>[ ] Per-site database assignment</li><li>[ ] User and permission management per engine</li><li>[ ] Backup and restore per database engine</li><li>[ ] Clear visibility into database configs and paths</li></ul><hr><h3 id="phase-4-—-production-readiness-safety-rc" tabindex="-1">Phase 4 — Production Readiness &amp; Safety (RC) <a class="header-anchor" href="#phase-4-—-production-readiness-safety-rc" aria-label="Permalink to &quot;Phase 4 — Production Readiness &amp; Safety (RC)&quot;">​</a></h3><p><strong>Goal:</strong> Make KiwiPanel safe and predictable for long-running servers.</p><ul><li>[ ] Non-destructive configuration validation</li><li>[ ] Pre-change checks and warnings</li><li>[ ] Configuration diff preview before applying changes</li><li>[ ] Rollback for failed operations</li><li>[ ] Versioned config snapshots</li><li>[ ] Read-only / audit mode</li><li>[ ] Upgrade safety checks</li></ul><hr><h3 id="phase-5-—-developer-ops-experience" tabindex="-1">Phase 5 — Developer &amp; Ops Experience <a class="header-anchor" href="#phase-5-—-developer-ops-experience" aria-label="Permalink to &quot;Phase 5 — Developer &amp; Ops Experience&quot;">​</a></h3><p><strong>Goal:</strong> Improve daily workflows for developers and sysadmins.</p><ul><li>[ ] Full CLI ↔ Web UI parity</li><li>[ ] Scriptable output (JSON, machine-readable)</li><li>[ ] Environment diagnostics and health checks</li><li>[ ] Resource limits per site (CPU / RAM)</li><li>[ ] Filesystem quotas</li><li>[ ] Backup scheduling and retention policies</li><li>[ ] Borg backup</li></ul><hr><h3 id="phase-6-—-extensibility-ecosystem" tabindex="-1">Phase 6 — Extensibility &amp; Ecosystem <a class="header-anchor" href="#phase-6-—-extensibility-ecosystem" aria-label="Permalink to &quot;Phase 6 — Extensibility &amp; Ecosystem&quot;">​</a></h3><p><strong>Goal:</strong> Grow the ecosystem without becoming bloated.</p><ul><li>[ ] Plugin / module system (sandboxed)</li><li>[ ] Hook system for install and lifecycle events</li><li>[ ] External monitoring integration (Prometheus-compatible)</li><li>[ ] WordPress Toolkit</li><li>[ ] Optional notification channels (Telegram, email)</li><li>[ ] Remote backup targets (object storage, S3-compatible)</li></ul><hr><h3 id="explicit-design-rules" tabindex="-1">Explicit Design Rules <a class="header-anchor" href="#explicit-design-rules" aria-label="Permalink to &quot;Explicit Design Rules&quot;">​</a></h3><p>To keep KiwiPanel focused, the following rules apply:</p><ul><li>No forced stacks or vendors</li><li>No hidden background services</li><li>No silent configuration changes</li><li>No proprietary formats</li><li>No one-click actions without visibility</li></ul><hr><h3 id="philosophy-going-forward" tabindex="-1">Philosophy Going Forward <a class="header-anchor" href="#philosophy-going-forward" aria-label="Permalink to &quot;Philosophy Going Forward&quot;">​</a></h3><p>KiwiPanel prioritizes:</p><ul><li><strong>Predictability over convenience</strong></li><li><strong>Visibility over abstraction</strong></li><li><strong>Standard Linux tools over custom orchestration</strong></li></ul><p>If a feature cannot be explained clearly or mapped directly to system behavior, it does not belong in KiwiPanel.</p>',39)])])}const g=i(o,[["render",n]]);export{u as __pageData,g as default};
